-- Création de la base de données midgar si elle n'existe pas
CREATE DATABASE IF NOT EXISTS midgar;
USE midgar;

-- Table defi
CREATE TABLE IF NOT EXISTS defi (
    id INT PRIMARY KEY AUTO_INCREMENT,
    titre VARCHAR(255) NOT NULL,
    description TEXT,
    theme VARCHAR(100),
    image_cover VARCHAR(500),
    date_debut DATE,
    date_fin DATE,
    date_limite DATE,
    statut ENUM('OUVERT', 'FERME', 'TERMINE', 'PLANIFIE') DEFAULT 'OUVERT',
    difficulte ENUM('FACILE', 'MOYEN', 'DIFFICILE') DEFAULT 'FACILE',
    createur_id INT NOT NULL,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Index pour améliorer les performances
CREATE INDEX idx_defi_statut ON defi(statut);
CREATE INDEX idx_defi_theme ON defi(theme);
CREATE INDEX idx_defi_createur ON defi(createur_id);
CREATE INDEX idx_defi_dates ON defi(date_debut, date_fin);

package com.example.app.exceptions;

/**
 * Exception personnalisée pour l'application Midgar
 * Utilisée pour les erreurs métier et de validation
 */
public class AppException extends Exception {

    private String errorCode;
    private String userMessage;

    /**
     * Constructeur simple avec message
     */
    public AppException(String message) {
        super(message);
        this.userMessage = message;
    }

    /**
     * Constructeur avec cause
     */
    public AppException(String message, Throwable cause) {
        super(message, cause);
        this.userMessage = message;
    }

    /**
     * Constructeur avec code d'erreur
     */
    public AppException(String errorCode, String message, String userMessage) {
        super(message);
        this.errorCode = errorCode;
        this.userMessage = userMessage;
    }

    /**
     * Constructeur complet
     */
    public AppException(String errorCode, String message, String userMessage, Throwable cause) {
        super(message, cause);
        this.errorCode = errorCode;
        this.userMessage = userMessage;
    }

    // Getters
    public String getErrorCode() {
        return errorCode;
    }

    public String getUserMessage() {
        return userMessage;
    }

    /**
     * Messages d'erreur prédéfinis
     */
    public static class ValidationError extends AppException {
        public ValidationError(String field, String message) {
            super("VALIDATION_ERROR", 
                  "Erreur de validation : " + field, 
                  field + " : " + message);
        }
    }

    public static class DatabaseError extends AppException {
        public DatabaseError(String operation, Throwable cause) {
            super("DATABASE_ERROR", 
                  "Erreur base de données lors de : " + operation,
                  "Une erreur s'est produite. Veuillez réessayer.",
                  cause);
        }
    }

    public static class NotFoundError extends AppException {
        public NotFoundError(String resource, int id) {
            super("NOT_FOUND", 
                  resource + " avec ID " + id + " non trouvé",
                  resource + " introuvable.");
        }
    }

    public static class UnauthorizedError extends AppException {
        public UnauthorizedError(String resource) {
            super("UNAUTHORIZED", 
                  "Accès non autorisé à : " + resource,
                  "Vous n'avez pas les permissions pour accéder à cette ressource.");
        }
    }
}

package com.example.app.utils;

import javafx.scene.control.Alert;
import javafx.scene.control.ButtonType;
import javafx.scene.control.Dialog;
import javafx.geometry.Insets;
import javafx.scene.layout.VBox;
import javafx.scene.text.Text;
import javafx.stage.StageStyle;
import java.util.Optional;

/**
 * Gestionnaire centralisé des alertes et dialogues
 * Fournit des méthodes pour afficher des messages utilisateur
 */
public class AlertUtil {

    private static final String DARK_THEME = 
        "-fx-background-color: #1a1a1a; " +
        "-fx-text-fill: #ffffff; " +
        "-fx-font-family: 'Segoe UI'; " +
        "-fx-font-size: 12;";

    /**
     * Affiche une alerte d'erreur
     */
    public static void showError(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.ERROR);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.setContentText(message);
        alert.showAndWait();
    }

    /**
     * Affiche une alerte d'erreur (surcharge)
     */
    public static void showError(String message) {
        showError("❌ Erreur", message);
    }

    /**
     * Affiche une alerte d'information
     */
    public static void showInfo(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.INFORMATION);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.setContentText(message);
        alert.showAndWait();
    }

    /**
     * Affiche une alerte d'information (surcharge)
     */
    public static void showInfo(String message) {
        showInfo("ℹ️ Information", message);
    }

    /**
     * Affiche une alerte d'avertissement
     */
    public static void showWarning(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.WARNING);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.setContentText(message);
        alert.showAndWait();
    }

    /**
     * Affiche une alerte d'avertissement (surcharge)
     */
    public static void showWarning(String message) {
        showWarning("⚠️ Avertissement", message);
    }

    /**
     * Affiche une alerte de confirmation
     * Retourne true si utilisateur a cliqué "OK"
     */
    public static boolean showConfirm(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.CONFIRMATION);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.setContentText(message);
        alert.getButtonTypes().setAll(ButtonType.OK, ButtonType.CANCEL);

        Optional<ButtonType> result = alert.showAndWait();
        return result.isPresent() && result.get() == ButtonType.OK;
    }

    /**
     * Affiche une alerte de confirmation (surcharge)
     */
    public static boolean showConfirm(String message) {
        return showConfirm("Confirmation", message);
    }

    /**
     * Affiche une alerte de confirmation de suppression
     */
    public static boolean showDeleteConfirm(String itemName) {
        return showConfirm("Confirmer la suppression", 
            "Êtes-vous sûr de vouloir supprimer '" + itemName + "' ?\n" +
            "Cette action est irréversible.");
    }

    /**
     * Affiche un dialogue avec une zone de texte éditable
     */
    public static Optional<String> showInputDialog(String title, String headerText, String promptText) {
        javafx.scene.control.TextInputDialog dialog = new javafx.scene.control.TextInputDialog();
        dialog.setTitle(title);
        dialog.setHeaderText(headerText);
        dialog.setContentText(promptText);
        return dialog.showAndWait();
    }
}

package com.example.app.utils;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;

public class MyDataBase {
    private final   String url="jdbc:mysql://localhost:3306/midgar";
    private   final   String user ="root";
    private   final String pws ="";

    private Connection connection;
    private static MyDataBase instance;
    private MyDataBase(){
        try {
            connection= DriverManager.getConnection(url,user,pws);
            System.out.println("connecter a la base de données");
        } catch (SQLException e) {
            System.out.println(e.getMessage());    }
    }
    public static MyDataBase getInstance(){
        if (instance==null){
            instance= new MyDataBase();

        }
        return instance;
    }

    public Connection getConnection() {
        return connection;
    }
}

